export interface DecodeSession {
  readonly id: string;
  push(chunk: ArrayBuffer | Uint8Array): Promise<void>;
  close(): Promise<void>;
  frames(): AsyncIterable<DecodeFrameEvent>;
  done(): Promise<ImageInfo>;
  cancel(reason?: string): Promise<void>;
}

export interface MsgDecodeChunk {
  type: "decode_chunk";
  sessionId: string;
  chunk: ArrayBuffer;           // transferred
}

export interface DecodeOptions {
  ...
  signal?: AbortSignal;
  onMetric?: (m: CodecMetric) => void;
}

export interface MsgDecodeCancel {
  type: "decode_cancel";
  sessionId: string;
  reason?: string;
}

export interface MsgDecodePause {
  type: "decode_pause";
  sessionId: string;
}

export interface MsgDecodeResume {
  type: "decode_resume";
  sessionId: string;
}
